/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../input/BTInputClear.css';

/*
 * BTInputDropdown — click-to-open dropdown field with floating panel.
 * Figma node 555-3041.
 *
 * Layout follows BTInput exactly — position:relative on the field div,
 * label is position:absolute inside it. No inner content wrapper.
 *
 * Visual structure (flex-row, height 48px — same as BTInputDate):
 * ┌── field (position:relative) ──────────────────────────────────┐
 * │  label (absolute, resting↔floating)  │  value  │  [×?]  │  [↓]  │
 * └────────────────────────────────────────────────────────────────┘
 */

/* ── Outer wrapper ───────────────────────────────────────────── */
.bt-input-dropdown__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field row ───────────────────────────────────────────────── */
/*
 * position: relative — required so the absolute label is positioned
 * relative to this field div, not a parent. Mirrors BTInput exactly.
 */
.bt-input-dropdown {
  position: relative;
  display: flex;
  align-items: center;
  height: 48px;                  /* Figma Default size: 48px */
  box-sizing: border-box;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  padding: 0 8px;
  gap: var(--space-sm);
  cursor: pointer;
  user-select: none;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When label is floating: add breathing room (mirrors BTInput--label-floating) */
.bt-input-dropdown--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* States */
.bt-input-dropdown--open     { border-color: var(--color-brand-primary); }
.bt-input-dropdown--error    { border-color: var(--text-error); }
.bt-input-dropdown--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Floating label ──────────────────────────────────────────── */
/*
 * position: absolute inside the position:relative field div.
 * left: 8px — no icon prefix, aligns to field padding.
 * Resting: centered vertically. Floating: small at top.
 */
.bt-input-dropdown__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-sm);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 48px); /* 8px start + 16px chevron + 8px clear + gap */
  transition: top        150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform  150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size  150ms cubic-bezier(0.4, 0, 0.2, 1),
              color      150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown--label-floating .bt-input-dropdown__label {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

/* Label color per state */
.bt-input-dropdown--open     .bt-input-dropdown__label { color: var(--color-brand-primary); }
.bt-input-dropdown--error    .bt-input-dropdown__label { color: var(--text-error); }
.bt-input-dropdown--disabled .bt-input-dropdown__label { color: var(--text-disabled); }

.bt-input-dropdown__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Value / placeholder text ────────────────────────────────── */
/*
 * flex: 1; height: 100% — fills available flex space, same as BTInput__field.
 * When floating: padding-top: 16px pushes text below the floating label.
 *   Container top padding (8px) + value padding-top (16px) = 24px from field top.
 *   Floating label: top 8px + line-height 16px = ends at 24px. Perfect alignment.
 */
.bt-input-dropdown__value {
  flex: 1;
  height: 100%;
  min-width: 0;
  display: flex;
  align-items: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When floating: push text down below the floating label.
   padding-top 14px (not 16) gives 2px breathing room for font descenders at 48px height. */
.bt-input-dropdown--label-floating .bt-input-dropdown__value {
  padding-top: 14px;
  align-items: flex-start;
}

/* Placeholder state (open but no value) */
.bt-input-dropdown__value--placeholder {
  color: var(--text-secondary);
}

.bt-input-dropdown--disabled .bt-input-dropdown__value { color: var(--text-disabled); }

/* ── Clear (×) button ────────────────────────────────────────── */
.bt-input-dropdown__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-dropdown__clear img,
.bt-input-dropdown__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Chevron ──────────────────────────────────────────────────── */
.bt-input-dropdown__chevron {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
  transition: transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown__chevron img,
.bt-input-dropdown__chevron svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-input-dropdown--open .bt-input-dropdown__chevron {
  transform: rotate(180deg);
  color: var(--color-brand-primary);
}
.bt-input-dropdown--error    .bt-input-dropdown__chevron { color: var(--text-error); }
.bt-input-dropdown--disabled .bt-input-dropdown__chevron { color: var(--text-disabled); }

/* ── Helper / error text ─────────────────────────────────────── */
.bt-input-dropdown__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-dropdown__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-dropdown__helper-text--error { color: var(--text-error); }

/* ── Small variant (size="small") ───────────────────────────────
 * ~40 px auto height.
 * Empty: py-12px  |  Floating: py-4px
 * Value text: 12 px (instead of 14 px for default).
 * Figma: size=Small in node 555-3041.
 */
.bt-input-dropdown--small {
  height: auto;
  padding-top: 12px;
  padding-bottom: 12px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown--small.bt-input-dropdown--label-floating {
  padding-top: 4px;
  padding-bottom: 4px;
}

/* In small floating state, label hugs the top edge at 4 px */
.bt-input-dropdown--small.bt-input-dropdown--label-floating .bt-input-dropdown__label {
  top: var(--space-xs);
}

/* Value: auto height (no 100% — container has no fixed height in small) */
.bt-input-dropdown--small .bt-input-dropdown__value {
  height: auto;
  font-size: var(--typography-font-size-xs);
}

/* Push value text below floating label */
.bt-input-dropdown--small.bt-input-dropdown--label-floating .bt-input-dropdown__value {
  padding-top: 16px;
  align-items: flex-start;
}

/* ── Dropdown panel (teleported to body) ─────────────────────── */
.bt-input-dropdown__panel {
  position: fixed;
  z-index: 1000;
  /* width set via JS to match trigger width exactly */
  box-sizing: border-box;
  overflow: hidden;
  opacity: 0;
  pointer-events: none;
  transition: opacity 120ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown__panel--visible {
  opacity: 1;
  pointer-events: auto;
}

/**
 * BTInputDropdown — Input-family dropdown select types.
 *
 * Figma node 555-3041.
 */
import type { BTDropdownItem } from '../dropdown-list/BTDropdownList.types';

export type BTInputDropdownSize = 'default' | 'small';

export interface BTInputDropdownProps<T = string> {
  /** Currently selected value — must match one of items[n].value */
  modelValue?: T | null;
  /** Floating label text */
  label?: string;
  /** Items to display in the panel */
  items: BTDropdownItem<T>[];
  /**
   * Show a search input at the top of the panel.
   * Filtering is done internally — parent does NOT need to filter items.
   * @default false
   */
  hasSearch?: boolean;
  /**
   * Field height variant.
   * - 'default' → 48px height
   * - 'small'   → auto height, smaller padding
   * @default 'default'
   */
  size?: BTInputDropdownSize;
  /** @default false */
  disabled?: boolean;
  /** @default false */
  readOnly?: boolean;
  /** @default false */
  required?: boolean;
  /** External error message — overrides internal validator error */
  errorText?: string;
  helperText?: string;
  /** Used for label `for` / aria — auto-generated if omitted */
  id?: string;
  /**
   * Text shown in the empty state (no items or no search match).
   * @default 'No result found.'
   */
  emptyLabel?: string;
  /**
   * Convert a BTDropdownItem to a display string shown in the field.
   * Defaults to `item.label ?? ''`.
   */
  getLabel?: (item: BTDropdownItem<T>) => string;
}

// Emits:
//   'update:modelValue'  (value: T | null)
//   'clear'              ()

/**
 * positionFloating — shared smart-flip positioning utility.
 *
 * Measures available space around a trigger element and places a floating
 * panel (already rendered in the DOM at position:fixed) below or above
 * depending on which direction has more room. Clamps horizontally so the
 * panel never overflows the viewport edges.
 *
 * Usage:
 *   // After the panel is in the DOM (watch flush:'post' or nextTick):
 *   positionBelow(triggerEl, panelEl, { gap: 4, margin: 8 });
 *
 * Also exported: positionDropdown — same algorithm but centres the panel
 * horizontally over an anchor element (for header pill dropdowns).
 */

export interface PositionOptions {
  /** Gap between trigger edge and panel edge. Default: 4. */
  gap?: number;
  /** Minimum distance from viewport edges. Default: 8. */
  margin?: number;
}

/**
 * Position a panel below or above `trigger`, left-aligned (then clamped).
 * Mutates `panel.style.top / left` and returns the resolved direction.
 */
export function positionBelow(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: PositionOptions = {},
): 'below' | 'above' {
  const { gap = 4, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Vertical: prefer below, flip above when there's not enough space ────────
  const spaceBelow = vh - tRect.bottom - gap;
  const spaceAbove = tRect.top - gap;
  const goAbove    = spaceBelow < pRect.height && spaceAbove >= pRect.height;

  const top = goAbove
    ? tRect.top  - pRect.height - gap
    : tRect.bottom + gap;

  // ── Horizontal: align to trigger start edge, clamp to viewport ─────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  let left = isRtl ? tRect.right - pRect.width : tRect.left;
  if (left + pRect.width > vw - margin) left = vw - margin - pRect.width;
  if (left < margin)                    left = margin;

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;

  return goAbove ? 'above' : 'below';
}

export type PopoverSide   = 'top' | 'bottom' | 'left' | 'right';
export type PopoverAlign  = 'start' | 'center' | 'end';

/**
 * Position a popover panel relative to a trigger with auto-flip on all axes.
 * Respects the requested `side` but flips to the opposite if there is no room.
 */
export function positionPopover(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: { side?: PopoverSide; align?: PopoverAlign; sideOffset?: number; margin?: number } = {},
): void {
  const { side = 'bottom', align = 'start', sideOffset = 8, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Resolve side with auto-flip ─────────────────────────────────────────────
  let resolvedSide = side;
  if (side === 'bottom') {
    const fits = vh - tRect.bottom - sideOffset >= pRect.height;
    if (!fits && tRect.top - sideOffset >= pRect.height) resolvedSide = 'top';
  } else if (side === 'top') {
    const fits = tRect.top - sideOffset >= pRect.height;
    if (!fits && vh - tRect.bottom - sideOffset >= pRect.height) resolvedSide = 'bottom';
  } else if (side === 'right') {
    const fits = vw - tRect.right - sideOffset >= pRect.width;
    if (!fits && tRect.left - sideOffset >= pRect.width) resolvedSide = 'left';
  } else /* left */ {
    const fits = tRect.left - sideOffset >= pRect.width;
    if (!fits && vw - tRect.right - sideOffset >= pRect.width) resolvedSide = 'right';
  }

  // ── Main axis ───────────────────────────────────────────────────────────────
  let top  = 0;
  let left = 0;
  if      (resolvedSide === 'bottom') top  = tRect.bottom + sideOffset;
  else if (resolvedSide === 'top')    top  = tRect.top - pRect.height - sideOffset;
  else if (resolvedSide === 'right')  left = tRect.right  + sideOffset;
  else /* left */                     left = tRect.left  - pRect.width - sideOffset;

  // ── Cross axis (alignment) — flip start/end in RTL ──────────────────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  const resolvedAlign = isRtl
    ? (align === 'start' ? 'end' : align === 'end' ? 'start' : align)
    : align;

  if (resolvedSide === 'top' || resolvedSide === 'bottom') {
    if      (resolvedAlign === 'start')  left = tRect.left;
    else if (resolvedAlign === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
    else /* end */                       left = tRect.right - pRect.width;

    // Clamp horizontally
    left = Math.min(left, vw - margin - pRect.width);
    left = Math.max(left, margin);
  } else {
    if      (align === 'start')  top = tRect.top;
    else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
    else /* end */               top = tRect.bottom - pRect.height;

    // Clamp vertically
    top = Math.min(top, vh - margin - pRect.height);
    top = Math.max(top, margin);
  }

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
}

/**
 * Position a small dropdown centred horizontally over `anchor`, below or above.
 * Used by BTCalendarHeader month/year pills.
 */
export function positionCentered(
  anchor: HTMLElement,
  dropdown: HTMLElement,
  opts: PositionOptions = {},
): void {
  const { gap = 4, margin = 8 } = opts;
  const aRect = anchor.getBoundingClientRect();
  const dRect = dropdown.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // Vertical: prefer below, flip above
  const spaceBelow = vh - aRect.bottom - gap;
  const spaceAbove = aRect.top - gap;
  const goAbove    = spaceBelow < dRect.height && spaceAbove >= dRect.height;

  const top = goAbove
    ? aRect.top  - dRect.height - gap
    : aRect.bottom + gap;

  // Horizontal: centre over anchor, clamp
  let left = aRect.left + aRect.width / 2 - dRect.width / 2;
  if (left + dRect.width > vw - margin) left = vw - margin - dRect.width;
  if (left < margin)                    left = margin;

  dropdown.style.top  = `${Math.round(top)}px`;
  dropdown.style.left = `${Math.round(left)}px`;
}
